/* ==UserStyle==
@name         Youtube Ambient mode for Zen Browser
@version      20260629.02.36
@namespace    ?
@description  Youtube Ambient mode for Zen Browser
@license      No License
==/UserStyle== */

@-moz-document domain("youtube.com") {
/* =========================================================================
     MASTER AMBILIGHT CONFIGURATION (V2 - Corrected Scroll Fix yeah)
     ========================================================================= */
:root {
    /* --- SPATIAL PARAMETERS --- */
    --ambi-scale: 4.0;
    --ambi-pos-y: 25%;
    --ambi-canvas-scale: 1.4;

    /* --- VISUAL PARAMETERS --- */
    --ambi-blur: 45px;
    --ambi-saturate: 400%;
    --ambi-brightness: 1.5;
    --ambi-contrast: 1.0;
    --ambi-opacity: 0.4;

    /* --- MASK PARAMETERS --- */
    --ambi-mask-start: 35%;
    --ambi-mask-end: 75%;
    --ambi-fade-time: 0.2s;

    /* --- UI AESTHETICS --- */
    --ambi-border-radius: 0px;
}

/* =========================================================================
     1. PAGE SCROLL FIX
     Prevents the expanded glow from causing horizontal scrollbars on the page
     ========================================================================= */
ytd-app,
body {
    overflow-x: hidden !important;
}

/* =========================================================================
     2. UI OVERRIDES
     ========================================================================= */
#ytd-player,
.html5-video-player,
.ytp-player-minimized,
video {
    border-radius: var(--ambi-border-radius) !important;
}

/* =========================================================================
     3. AMBILIGHT ENGINE
     ========================================================================= */
html body #cinematics,
html body #cinematics > div {
    display: flex !important;
    visibility: visible !important;
    background: transparent !important;
    box-shadow: none !important;
    isolation: isolate !important;
    pointer-events: none !important;
}

html body #cinematics > div > div {
    display: flex !important;
    visibility: visible !important;
    background: transparent !important;
    filter: blur(var(--ambi-blur)) saturate(var(--ambi-saturate)) brightness(var(--ambi-brightness)) contrast(var(--ambi-contrast)) !important;
    transform: scale(var(--ambi-scale)) translate3d(0, var(--ambi-pos-y), 0) !important;
    transform-style: preserve-3d !important;
    color-interpolation-filters: sRGB !important;
    opacity: var(--ambi-opacity) !important;
    mix-blend-mode: screen !important;
    will-change: transform, opacity, filter;
    transition: opacity var(--ambi-fade-time) linear !important;
}

html body #cinematics canvas {
    display: block !important;
    visibility: visible !important;
    -webkit-mask-image: radial-gradient(ellipse, rgba(0, 0, 0, 1) var(--ambi-mask-start), rgba(0, 0, 0, 0) var(--ambi-mask-end)) !important;
    mask-image: radial-gradient(ellipse, rgba(0, 0, 0, 1) var(--ambi-mask-start), rgba(0, 0, 0, 0) var(--ambi-mask-end)) !important;
    transform: scale(var(--ambi-canvas-scale)) translate3d(0, 0, 0) !important;
    backface-visibility: hidden !important;
    will-change: opacity, transform;
    image-rendering: auto !important;
    contain: strict !important;
    transition: none !important;
    animation: none !important;
}

/* =========================================================================
     4. UI CLEANUP
     ========================================================================= */
.ytp-glow-shadow,
#player-base,
ytd-watch-flexy[is-two-columns_] #columns {
    background: transparent !important;
    background-color: transparent !important;
    box-shadow: none !important;
}
}

/* ==UserStyle==
@name         Instagram Stories Anti Antirightclick
@namespace    USO Archive
@author       Jakub Kučera
@description  Enable Instagram Stories Right click
@version      20190603.08.19
@license      NONE
@preprocessor uso
==/UserStyle== */
@-moz-document domain("instagram.com") {
.yxA_V,.JSHyA,.zvitu,.vgS-T,.z6Odz,.yiMZG,.TxciK,.D8xaz,.O1flK {
    display:none !important;
    width:0 !important;
    height:0 !important;
    position:static !important;
    top:initial !important;
    left:initial !important;
    bottom:initial !important;
    right:initial !important;
}
}
